  ('judicial-cf446b4c-moex-00204', 'judicial-cf446b4c', 'judicial-cf446b4c-moex-112-e2754278', 'sub-judicial-cf446b4c-01', NULL, 'single_choice', '有關放火、失火罪的敘述，下列何者正確？', '["現供人使用之住宅或建築物，限於現有人所在的情形", "汽油彈是準失火罪所稱的「爆裂物」", "對無主物放火，不成立放火罪", "行為人故意引燃火源，係屬故意放火罪"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:22+00:00", "source_pdf_sha1": "d4be12aadcc3", "answer_pdf_sha1": "5836207ad078", "source_family": "moex-gov-tw", "moex": {"exam_code": "112130", "c": "204", "s": "0505", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "刑法概要", "year": "112", "exam_name": "112年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 35, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "執達員"}'::jsonb, NULL),
  ('judicial-cf446b4c-moex-00205', 'judicial-cf446b4c', 'judicial-cf446b4c-moex-112-e2754278', 'sub-judicial-cf446b4c-01', NULL, 'single_choice', '甲意圖供行使之用而偽造政府發行之消費券。關於甲之行為構成何罪？', '["偽造貨幣罪", "偽造有價證券罪", "偽造度量衡罪", "偽造支付工具罪"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:22+00:00", "source_pdf_sha1": "d4be12aadcc3", "answer_pdf_sha1": "5836207ad078", "source_family": "moex-gov-tw", "moex": {"exam_code": "112130", "c": "204", "s": "0505", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "刑法概要", "year": "112", "exam_name": "112年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 36, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "執達員"}'::jsonb, NULL),
  ('judicial-cf446b4c-moex-00206', 'judicial-cf446b4c', 'judicial-cf446b4c-moex-112-e2754278', 'sub-judicial-cf446b4c-01', NULL, 'single_choice', '甲先偽造私文書後，進而拿此偽造的私文書立即行使，甲同時涉犯刑法第210條及第216條兩罪，依實務 見解，該兩罪應如何競合？', '["想像競合", "吸收關係", "集合犯", "數罪併罰"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:22+00:00", "source_pdf_sha1": "d4be12aadcc3", "answer_pdf_sha1": "5836207ad078", "source_family": "moex-gov-tw", "moex": {"exam_code": "112130", "c": "204", "s": "0505", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "刑法概要", "year": "112", "exam_name": "112年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 37, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "執達員"}'::jsonb, NULL),
  ('judicial-cf446b4c-moex-00207', 'judicial-cf446b4c', 'judicial-cf446b4c-moex-112-e2754278', 'sub-judicial-cf446b4c-01', NULL, 'single_choice', '甲欲性侵乙，一手壓住乙的嘴巴，另一手拉脫其褲子，雙方生殖器官尚未接觸時，即遭制伏，依實務見解， 關於甲之行為應如何論罪？', '["成立強制猥褻罪未遂", "成立強制性交罪未遂", "成立強制性交罪預備犯", "成立強制性交罪既遂犯"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:22+00:00", "source_pdf_sha1": "d4be12aadcc3", "answer_pdf_sha1": "5836207ad078", "source_family": "moex-gov-tw", "moex": {"exam_code": "112130", "c": "204", "s": "0505", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "刑法概要", "year": "112", "exam_name": "112年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 38, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "執達員"}'::jsonb, NULL),
  ('judicial-cf446b4c-moex-00208', 'judicial-cf446b4c', 'judicial-cf446b4c-moex-112-e2754278', 'sub-judicial-cf446b4c-01', NULL, 'single_choice', '有關刑法第266條賭博罪，下列敘述何者錯誤？', '["賭博行為是指以不確定的結果來決定財物的輸贏，所以詐賭不是賭博", "家人之間以球賽結果打賭輸贏飲料，不得以賭博罪加以處罰", "公然賭博罪最重僅處以罰金刑", "以網路帳號在特定網站賭博下注，不得以賭博罪加以處罰"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:22+00:00", "source_pdf_sha1": "d4be12aadcc3", "answer_pdf_sha1": "5836207ad078", "source_family": "moex-gov-tw", "moex": {"exam_code": "112130", "c": "204", "s": "0505", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "刑法概要", "year": "112", "exam_name": "112年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 39, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "執達員"}'::jsonb, NULL),
  ('judicial-cf446b4c-moex-00209', 'judicial-cf446b4c', 'judicial-cf446b4c-moex-112-e2754278', 'sub-judicial-cf446b4c-01', NULL, 'single_choice', '甲罹患癌症，久病厭世，請求乙調製致命藥劑，甲取得後自行服用而死亡，乙之行為如何評價？', '["教唆自殺", "幫助自殺", "受囑託而殺人", "得承諾而殺人"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:22+00:00", "source_pdf_sha1": "d4be12aadcc3", "answer_pdf_sha1": "5836207ad078", "source_family": "moex-gov-tw", "moex": {"exam_code": "112130", "c": "204", "s": "0505", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "刑法概要", "year": "112", "exam_name": "112年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 40, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "執達員"}'::jsonb, NULL),
  ('judicial-cf446b4c-moex-00210', 'judicial-cf446b4c', 'judicial-cf446b4c-moex-112-e2754278', 'sub-judicial-cf446b4c-01', NULL, 'single_choice', '關於傷害罪，下列敘述何者錯誤？', '["過失致他人受輕傷或重傷，均屬犯罪行為", "刑法上的傷害可以分為普通傷害與重傷害", "普通傷害罪不處罰未遂犯", "身體髮膚，受之父母。因此傷害自己身體的行為，也構成傷害罪"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:22+00:00", "source_pdf_sha1": "d4be12aadcc3", "answer_pdf_sha1": "5836207ad078", "source_family": "moex-gov-tw", "moex": {"exam_code": "112130", "c": "204", "s": "0505", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "刑法概要", "year": "112", "exam_name": "112年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 41, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "執達員"}'::jsonb, NULL),
  ('judicial-cf446b4c-moex-00211', 'judicial-cf446b4c', 'judicial-cf446b4c-moex-112-e2754278', 'sub-judicial-cf446b4c-01', NULL, 'single_choice', '關於遺棄罪，下列敘述何者錯誤？', '["依刑法第293條、294條，遺棄行為須產生死亡或重傷結果，始構成遺棄罪", "刑法第294條之遺棄罪設有加重結果犯規定，對遺棄而致人於死或重傷者加重處罰", "依刑法第294條，對於無自救力之人，依法令或契約應扶助、養育或保護而遺棄之，構成遺棄罪，其中 「法令」包括民法", "對於直系血親尊親屬犯刑法第294條之罪者，加重其刑至二分之一"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:22+00:00", "source_pdf_sha1": "d4be12aadcc3", "answer_pdf_sha1": "5836207ad078", "source_family": "moex-gov-tw", "moex": {"exam_code": "112130", "c": "204", "s": "0505", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "刑法概要", "year": "112", "exam_name": "112年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 42, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "執達員"}'::jsonb, NULL),
  ('judicial-cf446b4c-moex-00212', 'judicial-cf446b4c', 'judicial-cf446b4c-moex-112-e2754278', 'sub-judicial-cf446b4c-01', NULL, 'single_choice', '關於刑法第306條無故侵入住宅罪之成立要件，依實務見解，下列敘述何者錯誤？', '["無故是指無正當理由", "本罪處罰的行為，僅限於積極侵入行為", "侵入客體除住宅外，也包括船艦在內", "得到同意而進入他人住宅，並非無故侵入"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:22+00:00", "source_pdf_sha1": "d4be12aadcc3", "answer_pdf_sha1": "5836207ad078", "source_family": "moex-gov-tw", "moex": {"exam_code": "112130", "c": "204", "s": "0505", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "刑法概要", "year": "112", "exam_name": "112年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 43, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "執達員"}'::jsonb, NULL),
  ('judicial-cf446b4c-moex-00213', 'judicial-cf446b4c', 'judicial-cf446b4c-moex-112-e2754278', 'sub-judicial-cf446b4c-01', NULL, 'single_choice', 'A的妻子B懷疑A有外遇，乃有償委託甲在A經常使用的汽車上裝設GPS，藉此蒐集A之行蹤，依實務 見解，甲的行為要如何論罪？', '["構成刑法第315條之1的無故以電磁紀錄竊錄他人非公開活動之犯罪", "構成刑法第318條之1的無故洩漏因利用電腦知悉或持有他人秘密之犯罪", "構成刑法第317條的無故洩漏依契約有守因業務知悉工商秘密義務之犯罪", "構成刑法第316條的無故洩漏因業務知悉或持有他人秘密之犯罪"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:22+00:00", "source_pdf_sha1": "d4be12aadcc3", "answer_pdf_sha1": "5836207ad078", "source_family": "moex-gov-tw", "moex": {"exam_code": "112130", "c": "204", "s": "0505", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "刑法概要", "year": "112", "exam_name": "112年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 44, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "執達員"}'::jsonb, NULL)
